#include <stdio.h>
#define VELICINA 5

int main() {
    int niz1[VELICINA], niz2[VELICINA];
    int i, min;
   
    /* unos niza */
    for (i = 0; i < VELICINA; ++i) {
        printf("Unesite %d. broj: ", i+1);
        scanf("%d", &niz1[i]);
    }
    
    /* kopiranje elemenata u drugi niz */
    for (i = 0; i < VELICINA; i++) {
        niz2[i] = niz1[i];
    }

    /* ispis drugog niza */
    printf("\nElementi drugog niza su: ");
    for (i = 0; i < VELICINA; i++) {
        printf("%d ", niz2[i]);
    }

    return 0;
}
